#include <stddef.h>   /* size_t */
#include <string.h>   /* memcpy */
#include <stdio.h>    /* printf */

/* ------------------------------------------------------------------
 * safe_copy
 * ------------------------------------------------------------------
 * Copies up to 'n' bytes from 'src' to 'dest'.
 *
 * Parameters:
 *   dest      – pointer to the destination buffer
 *   dest_size – size of the destination buffer in bytes
 *   src       – pointer to the source buffer
 *   n         – number of bytes requested to copy
 *
 * Returns:
 *   0 on success
 *   -1 if dest_size is insufficient (no copy performed)
 *   -2 if any pointer is NULL
 *
 * Note: The caller must ensure that 'src' points to at least 'n' bytes.
 * ------------------------------------------------------------------*/
int safe_copy(void *dest, size_t dest_size, const void *src, size_t n)
{
    /* Basic sanity checks */
    if (!dest || !src) {
        return -2; /* NULL pointer error */
    }

    /* Ensure we do not write past the destination buffer */
    if (n > dest_size) {
        return -1; /* Destination too small */
    }

    /* Perform the copy */
    memcpy(dest, src, n);
    return 0; /* Success */
}

/* ------------------------------------------------------------------
 * safe_strlen
 * ------------------------------------------------------------------
 * Computes the length of a null‑terminated string.
 *
 * Parameters:
 *   s – pointer to the string
 *
 * Returns:
 *   Length of the string (number of characters before the NUL byte)
 *   0 if s is NULL
 * ------------------------------------------------------------------*/
size_t safe_strlen(const char *s)
{
    if (!s) {
        return 0;
    }

    /* Use a loop to avoid relying on library implementations that may
       not be safe in all contexts. */
    size_t len = 0;
    while (s[len] != '\0') {
        len++;
    }
    return len;
}

/* ------------------------------------------------------------------
 * Example usage
 * ------------------------------------------------------------------*/
int main(void)
{
    /* Destination buffer: 6 bytes (5 for "Hello" + 1 for NUL) */
    char dest[6] = {0};

    /* Source string literal */
    const char *src = "Hello";

    /* Compute the number of bytes to copy (including the NUL terminator) */
    size_t bytes_to_copy = safe_strlen(src) + 1; /* +1 for NUL */

    /* Perform the copy safely */
    int rc = safe_copy(dest, sizeof(dest), src, bytes_to_copy);
    if (rc != 0) {
        fprintf(stderr, "Error: safe_copy failed (code %d)\n", rc);
        return 1;
    }

    /* Verify the result */
    printf("Copied string: \"%s\"\n", dest);
    return 0;
}
