/*  safe_print_arg.c
 *
 *  Demonstrates safe handling of command‑line arguments and atoi().
 *  The program expects at least two arguments:
 *      argv[0] – program name
 *      argv[1] – an integer string specifying the index to print
 *      argv[2] … argv[argc-1] – the arguments that can be printed
 *
 *  Usage:
 *      ./safe_print_arg 3 hello world foo bar
 *  Output:
 *      foo
 *
 *  Compile with:
 *      gcc -Wall -Wextra -O2 -o safe_print_arg safe_print_arg.c
 */

#include <stdio.h>
#include <stdlib.h>
#include <errno.h>
#include <limits.h>

/* Helper: convert string to integer with error checking */
static int safe_atoi(const char *str, int *out)
{
    char *endptr;
    long val;

    errno = 0;                /* reset errno before call */
    val = strtol(str, &endptr, 10);

    /* Check for conversion errors */
    if (errno != 0 || endptr == str || *endptr != '\0')
        return -1;           /* invalid integer string */

    /* Ensure the value fits in an int */
    if (val < INT_MIN || val > INT_MAX)
        return -1;

    *out = (int)val;
    return 0;
}

int main(int argc, char *argv[])
{
    /* Need at least two arguments: argv[1] (index) and one more to print */
    if (argc < 3) {
        fprintf(stderr, "Usage: %s <index> <arg1> [arg2 ...]\n", argv[0]);
        return EXIT_FAILURE;
    }

    int index;
    if (safe_atoi(argv[1], &index) != 0) {
        fprintf(stderr, "Error: '%s' is not a valid integer index.\n", argv[1]);
        return EXIT_FAILURE;
    }

    /* argv[0] is the program name, so the first user argument is argv[1].
       The user wants to print the argument at the position specified by
       the integer index.  We interpret the index as 0‑based relative to
       argv[1] (i.e., argv[1] is index 0). */
    int target_arg = 1 + index;   /* shift by 1 to account for argv[0] */

    if (target_arg <= 0 || target_arg >= argc) {
        fprintf(stderr, "Error: index %d out of bounds (valid range 0 to %d).\n",
                index, argc - 2);
        return EXIT_FAILURE;
    }

    printf("%s\n", argv[target_arg]);

    return EXIT_SUCCESS;
}
```

