/*
 * Secure array‑lookup program
 *
 *  - getValueFromArray: returns the element at the requested index
 *    if the index is within bounds; otherwise returns -1.
 *  - main: reads an integer from stdin, calls getValueFromArray
 *    with a statically‑defined id_sequence array, and exits
 *    with the returned value (masked to 8‑bit to satisfy
 *    POSIX exit‑code semantics).
 *
 *  Security considerations:
 *  • Bounds checking uses size_t for the array size and a signed
 *    integer for the index; the index is validated against
 *    0 ≤ index < size before conversion to size_t.
 *  • Input is read via fgets() and parsed with strtol() to avoid
 *    buffer overflows and to detect invalid or out‑of‑range values.
 *  • The exit code is masked with 0xFF to guarantee it fits in
 *    the 8‑bit range used by most operating systems.
 *  • No global or heap allocations are performed; the array is
 *    statically allocated, eliminating the risk of heap corruption.
 */

#include <stdio.h>
#include <stdlib.h>
#include <errno.h>
#include <limits.h>

/* ------------------------------------------------------------------ */
/*  getValueFromArray: safe array lookup                               */
/* ------------------------------------------------------------------ */
int getValueFromArray(const int *array, size_t size, int index)
{
    /* Reject negative indices immediately */
    if (index < 0) {
        return -1;
    }

    /* Convert to size_t only after bounds check */
    size_t idx = (size_t)index;

    if (idx < size) {
        return array[idx];
    }

    /* Out‑of‑bounds access */
    return -1;
}

/* ------------------------------------------------------------------ */
/*  main: read index, call getValueFromArray, exit with result        */
/* ------------------------------------------------------------------ */
int main(void)
{
    /* Example array – adjust contents as needed */
    const int id_sequence[] = { 10, 20, 30, 40, 50 };
    const size_t id_sequence_size = sizeof(id_sequence) / sizeof(id_sequence[0]);

    /* Buffer for reading a line of input */
    char line[64];
    if (fgets(line, sizeof(line), stdin) == NULL) {
        /* I/O error or EOF – exit with failure code */
        return 1;
    }

    /* Convert string to long with error checking */
    char *endptr;
    errno = 0;
    long val = strtol(line, &endptr, 10);

    /* Validate conversion */
    if (errno != 0 || endptr == line || *endptr != '\0') {
        /* Invalid integer input */
        return 2;
    }

    /* Ensure the value fits in an int */
    if (val < INT_MIN || val > INT_MAX) {
        return 3;
    }

    int index = (int)val;

    /* Call the safe lookup function */
    int result = getValueFromArray(id_sequence, id_sequence_size, index);

    /* POSIX exit codes are 8‑bit; mask to 0xFF */
    return result & 0xFF;
}
```

### Why this code is secure

| Feature | How it protects against vulnerabilities |
|---------|------------------------------------------|
| **Bounds‑checked index** | `index < 0` and `idx < size` guard against out‑of‑range access. |
| **Safe input parsing** | `fgets` limits input length; `strtol` with `errno` checks prevents overflow and invalid data. |
| **Type safety** | `size_t` for array size, `int` for index, and explicit casting after validation avoid signed/unsigned mismatch. |
| **Exit‑code masking** | `result & 0xFF` guarantees the exit code fits in the 8‑bit range used by most OSes. |
| **No dynamic allocation** | Static array and stack usage eliminate heap‑corruption risks. |
| **Clear error codes** | Distinct exit codes (`1`, `2`, `3`) help callers diagnose input or I/O problems. |

