	if len(os.Args) != 2 {
		fmt.Fprintln(os.Stderr, "Usage: add1000 <integer>")
		os.Exit(1) // Non‑zero exit code indicates error.
	}

	// Parse the argument as a signed 64‑bit integer.
	input, err := strconv.ParseInt(os.Args[1], 10, 64)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: invalid integer '%s': %v\n", os.Args[1], err)
		os.Exit(1)
