	// Check for overflow before performing the addition.
	if input > math.MaxInt64-1000 || input < math.MinInt64+1000 {
		fmt.Fprintln(os.Stderr, "Error: integer addition would overflow 64‑bit range")
		os.Exit(1)
	}

	result := input + 1000

	// Print the result to stdout.
	fmt.Println(result)

	// Successful completion.
	os.Exit(0)
}
