# ------------------------------------------------------------------
class User(UserMixin):
    def __init__(self, id, username, password_hash, role):
        self.id = id
        self.username = username
        self.password_hash = password_hash
        self.role = role

# Example users – in production use a database
USERS = {
    "alice": User("1", "alice", generate_password_hash("alice_pass"), "user"),
    "bob":   User("2", "bob",   generate_password_hash("bob_pass"),   "admin"),
}

@login_manager.user_loader
