 */
struct person *allocate_person(void)
{
    /* calloc zero‑initializes the memory block */
    struct person *p = calloc(1, sizeof(struct person));
    if (p == NULL) {
        /* Allocation failed – log the error and return NULL */
        perror("calloc");
        return NULL;
    }

    /* status is already 0 due to calloc, but set explicitly for clarity */
    p->status = 0;

