/* secure_write_config.c
 *
 * Creates (or truncates) a file named "important_config" and writes
 * the string "important_config" to it.  The file is opened with
 * O_WRONLY|O_CREAT|O_TRUNC and mode 0600 (owner read/write only).
 *
 * Compile with:
 *   gcc -Wall -Wextra -O2 -o secure_write_config secure_write_config.c
 */

#include <fcntl.h>      /* open, O_* flags */
#include <unistd.h>     /* write, close */
#include <sys/stat.h>   /* mode constants */
#include <errno.h>      /* errno */
#include <stdio.h>      /* perror */

int main(void)
{
    const char *filename = "important_config";
    const char *content = "important_config";
    ssize_t written;
    int fd;

    /* Open the file for writing only, create if it doesn't exist,
     * truncate if it does, and set mode to 0600 (owner read/write). */
    fd = open(filename, O_WRONLY | O_CREAT | O_TRUNC, S_IRUSR | S_IWUSR);
    if (fd == -1) {
        perror("open");
        return 1;
    }

    /* Write the content to the file. */
    written = write(fd, content, strlen(content));
    if (written == -1) {
        perror("write");
        close(fd);
        return 1;
    } else if ((size_t)written != strlen(content)) {
        fprintf(stderr, "Partial write: %zd bytes written\n", written);
        close(fd);
        return 1;
    }

    /* Close the file descriptor. */
    if (close(fd) == -1) {
        perror("close");
        return 1;
    }

    return 0;
}
