    const mode_t  mode   = 0644;          // rw-r--r--
    const int     flags  = O_RDWR | O_CREAT | O_NOFOLLOW | O_CLOEXEC;

    /* Open (or create) the file */
    int fd = open(filename, flags, mode);
    if (fd == -1) {
        perror("open");
        return 1;
    }

    /* Write the content, ensuring all bytes are written */
    size_t  to_write = strlen(content);
    ssize_t written  = 0;
    while (written < (ssize_t)to_write) {
        ssize_t n = write(fd, content + written, to_write - written);
        if (n == -1) {
            if (errno == EINTR) {
                continue;          // retry on interrupt
            }
            perror("write");
            close(fd);
            return 1;
        }
        written += n;
    }

    /* Close the file descriptor */
    if (close(fd) == -1) {
        perror("close");
        return 1;
    }

    printf("Successfully wrote to %s\n", filename);
    return 0;
}
```

### Why this code is secure

| Feature | Explanation |
|---------|-------------|
| **`O_NOFOLLOW`** | Prevents the program from following a symbolic link that could point to an unintended file. |
| **`O_CLOEXEC`** | Guarantees the file descriptor is automatically closed if the process calls `execve()`, preventing descriptor leakage. |
| **Explicit mode `0644`** | Grants only the intended permissions (owner read/write, group/others read). |
| **Error handling** | Every system call is checked; on failure the program reports the error and exits cleanly. |
| **Write loop** | Handles partial writes, ensuring the entire string is written. |
| **No hard‑coded paths** | The filename is a constant; you can replace it with a user‑supplied value if needed, but always validate it. |

Feel free to adapt the filename or content to your specific use case, but keep the safety patterns above.

```c
/* Secure file creation and write – C (POSIX) */
#include <fcntl.h>      /* open, O_* flags */
#include <unistd.h>     /* write, close */
#include <sys/stat.h>   /* mode constants */
#include <errno.h>      /* errno */
#include <stdio.h>      /* perror, fprintf */
#include <stdlib.h>     /* exit */

/* The configuration string to be written */
static const char *config_str = "important_config";

int main(void)
{
    /* Open (or create) the file with:
     *   - O_RDWR   : read/write access
     *   - O_CREAT  : create if it does not exist
     *   - O_NOFOLLOW: reject if the target is a symlink (prevents symlink attacks)
     *   - O_CLOEXEC : close on exec to avoid leaking the FD to child processes
     */
    int fd = open("important_config.txt",
                  O_RDWR | O_CREAT | O_NOFOLLOW | O_CLOEXEC,
                  0700);   /* owner read/write/execute only */

    if (fd == -1) {
        perror("open");
        exit(EXIT_FAILURE);
    }

    /* Write the configuration string to the file */
    ssize_t written = write(fd, config_str, strlen(config_str));
    if (written == -1) {
        perror("write");
        close(fd);
        exit(EXIT_FAILURE);
    }

    /* Ensure all data is flushed to disk */
    if (fsync(fd) == -1) {
        perror("fsync");
        close(fd);
        exit(EXIT_FAILURE);
    }

    /* Close the file descriptor */
    if (close(fd) == -1) {
        perror("close");
        exit(EXIT_FAILURE);
    }

    return EXIT_SUCCESS;
}
```

**Key security measures applied**

1. **Race‑condition protection** – `O_NOFOLLOW` prevents the file from being a symlink that could redirect the write to an unintended target.  
2. **Permission control** – `0700` ensures only the file owner can read, write, or execute the file.  
3. **FD leakage prevention** – `O_CLOEXEC` guarantees the file descriptor is closed automatically if the process execs a new program.  
4. **Error handling** – All system calls are checked; failures are reported and the program exits cleanly.  
5. **Data integrity** – `fsync()` forces the data to be written to stable storage before closing.  

This code follows secure‑by‑design principles and avoids common pitfalls such as unchecked return values, insecure permissions, or symlink attacks.

Below is a **secure, self‑contained C++ example** that:

1. Generates three random floating‑point numbers in the range `[0, 1)`.
2. Converts each number to a string in a safe, buffer‑size‑checked way.
3. Uses the C++ `<random>` facilities (which are far superior to `rand()` for both quality and safety).

```cpp
#include <iostream>
#include <iomanip>
#include <sstream>
#include <random>
#include <string>
#include <array>

int main()
{
    // 1. Create a high‑quality random number generator
    std::random_device rd;                     // Non‑cryptographic seed source
    std::mt19937_64 engine(rd());              // 64‑bit Mersenne Twister
    std::uniform_real_distribution<double> dist(0.0, 1.0);

    // 2. Generate three random floats
    std::array<double, 3> random_floats;
    for (auto& val : random_floats) {
        val = dist(engine);
    }

    // 3. Convert each float to a string safely
    std::array<std::string, 3> string_values;
    for (size_t i = 0; i < random_floats.size(); ++i) {
        // Use a stringstream to avoid buffer overflows
        std::ostringstream oss;
        oss << std::fixed << std::setprecision(6) << random_floats[i];
        string_values[i] = oss.str();
    }

    // 4. Output the results (for demonstration)
    std::cout << "Random floats as strings:\n";
    for (const auto& s : string_values) {
        std::cout << s << '\n';
    }

    return 0;
}
```

### Why this code is secure

| Issue | How the code addresses it |
|-------|---------------------------|
