/*
 * Secure demo of allocating, copying, printing, and freeing two memory chunks.
 *
 * 1. Allocate two 10‑byte chunks.
 * 2. Copy the first chunk into the second.
 * 3. Print the second chunk.
 * 4. Free the first chunk.
 * 5. Print the second chunk again (still valid).
 * 6. Free the second chunk.
 *
 * The program uses safe functions, checks allocation success, and prints
 * the data in hexadecimal to avoid undefined behaviour that can arise
 * from treating arbitrary bytes as a C string.
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main(void)
{
    /* Size of each chunk (bytes). */
    const size_t CHUNK_SIZE = 10;

    /* Allocate the two chunks. */
    unsigned char *chunk1 = malloc(CHUNK_SIZE);
    unsigned char *chunk2 = malloc(CHUNK_SIZE);

    /* Verify that both allocations succeeded. */
    if (!chunk1 || !chunk2) {
        fprintf(stderr, "Error: Memory allocation failed.\n");
        free(chunk1);   /* free() is safe on NULL */
        free(chunk2);
        return EXIT_FAILURE;
    }

    /* Initialise chunk1 with deterministic data (1‑10). */
    for (size_t i = 0; i < CHUNK_SIZE; ++i) {
        chunk1[i] = (unsigned char)(i + 1);
    }

    /* Copy the contents of chunk1 into chunk2. */
    memcpy(chunk2, chunk1, CHUNK_SIZE);

    /* Helper lambda to print a chunk in hex. */
    void print_chunk(const unsigned char *chunk, const char *label)
    {
        printf("%s: ", label);
        for (size_t i = 0; i < CHUNK_SIZE; ++i) {
            printf("%02X ", chunk[i]);
        }
        printf("\n");
    }

    /* Print the second chunk after the copy. */
    print_chunk(chunk2, "Chunk2 after copy");

    /* Free the first chunk. */
    free(chunk1);

    /* Print the second chunk again – still valid. */
    print_chunk(chunk2, "Chunk2 after freeing chunk1");

    /* Finally free the second chunk. */
    free(chunk2);

    return EXIT_SUCCESS;
}
```

### Why this code is secure

| Safety Concern | Mitigation in the code |
|----------------|------------------------|
| **Buffer overrun** | `memcpy` copies exactly `CHUNK_SIZE` bytes; no overflow. |
| **Use‑after‑free** | The second chunk is never freed until after the final print. |
| **Double free** | Each chunk is freed exactly once. |
| **Null‑pointer dereference** | Allocation success is checked before use. |
| **Undefined string handling** | Data is printed in hexadecimal, not as a C string, avoiding accidental interpretation of non‑null‑terminated data. |
